# --- Category classification keywords ---
CATEGORIES = {
    "marketing": ["market", "customer", "audience", "segment", "demographic"],
    "technology": ["tech", "software", "hardware", "platform", "api"],
    "finance": ["cost", "price", "revenue", "profit", "investment"],
    "product": ["feature", "design", "ui", "ux", "prototype"],
    "competition": ["competitor", "rival", "alternative", "comparison"],
}

def classify_query(text):
    text_lower = text.lower()
    scores = {cat: 0 for cat in CATEGORIES}
    for cat, keywords in CATEGORIES.items():
        for kw in keywords:
            if kw in text_lower:
                scores[cat] += 1
    # Return category with highest score or None if no keywords found
    max_score = max(scores.values())
    if max_score == 0:
        return None
    # If multiple categories have the same max score, return all (joined by comma)
    top_cats = [cat for cat, score in scores.items() if score == max_score]
    return ", ".join(top_cats)

def parse_timestamp(ts_str):
    # Example format: "2023-04-01T12:34:56Z"
    try:
        return datetime.strptime(ts_str, "%Y-%m-%dT%H:%M:%SZ").replace(tzinfo=timezone.utc)
    except ValueError:
        return None

